import React, { useEffect, useState } from 'react';
import api from '../api';

export default function MapaConductores() {
  const [conductores, setConductores] = useState([]);
  const [cargando, setCargando] = useState(true);

  useEffect(() => {
    const cargar = async () => {
      try {
        const res = await api.get('/users/conductores/en-servicio');
        setConductores(res.data.filter(c => c.ubicacionActual?.lat));
      } catch {}
      finally { setCargando(false); }
    };
    cargar();
    const intervalo = setInterval(cargar, 15000);
    return () => clearInterval(intervalo);
  }, []);

  if (cargando) return <p className="loading">Cargando mapa...</p>;

  return (
    <div>
      <h2 className="titulo">📍 Conductores en servicio ({conductores.length})</h2>

      {conductores.length === 0 ? (
        <div style={estilos.vacio}>
          <p style={{ fontSize: 48 }}>🚕</p>
          <p style={{ color: '#999' }}>No hay conductores en servicio</p>
        </div>
      ) : (
        <>
          {/* Mapa con OpenStreetMap (gratis, sin API key) */}
          <div style={estilos.mapaContainer}>
            <iframe
              title="Mapa conductores"
              width="100%"
              height="400"
              style={{ border: 0, borderRadius: 16 }}
              loading="lazy"
              src={`https://www.openstreetmap.org/export/embed.html?bbox=${(conductores[0]?.ubicacionActual?.lng || -73.17) - 0.05}%2C${(conductores[0]?.ubicacionActual?.lat || 7.08) - 0.03}%2C${(conductores[0]?.ubicacionActual?.lng || -73.17) + 0.05}%2C${(conductores[0]?.ubicacionActual?.lat || 7.08) + 0.03}&layer=mapnik&marker=${conductores[0]?.ubicacionActual?.lat || 7.08}%2C${conductores[0]?.ubicacionActual?.lng || -73.17}`}
            />
          </div>

          {/* Lista de conductores */}
          <div style={estilos.listaGrid}>
            {conductores.map(c => (
              <div key={c.uid} style={estilos.conductorCard}>
                <div style={estilos.conductorHeader}>
                  {c.fotoPerfil ? (
                    <img src={c.fotoPerfil} alt="" style={estilos.foto} />
                  ) : (
                    <div style={estilos.fotoPlaceholder}>
                      {c.nombre?.charAt(0)?.toUpperCase()}
                    </div>
                  )}
                  <div>
                    <p style={estilos.nombre}>{c.nombre}</p>
                    <p style={estilos.placa}>{c.placa}</p>
                  </div>
                </div>
                <div style={estilos.ubicacionInfo}>
                  <p style={estilos.coordenadas}>
                    📍 {c.ubicacionActual?.lat?.toFixed(4)}, {c.ubicacionActual?.lng?.toFixed(4)}
                  </p>
                  <p style={estilos.actualizado}>
                    Actualizado: {c.ubicacionActual?.actualizadoEn ? new Date(c.ubicacionActual.actualizadoEn).toLocaleTimeString('es-CO') : '—'}
                  </p>
                  <a
                    href={`https://www.google.com/maps?q=${c.ubicacionActual?.lat},${c.ubicacionActual?.lng}`}
                    target="_blank"
                    rel="noopener noreferrer"
                    style={estilos.linkMapa}
                  >
                    🗺️ Ver en Google Maps
                  </a>
                </div>
              </div>
            ))}
          </div>
        </>
      )}
    </div>
  );
}

const estilos = {
  vacio: { textAlign: 'center', padding: 60 },
  mapaContainer: { marginBottom: 24, borderRadius: 16, overflow: 'hidden', boxShadow: '0 2px 12px rgba(0,0,0,0.1)' },
  listaGrid: { display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(300px, 1fr))', gap: 16 },
  conductorCard: { background: '#fff', borderRadius: 14, padding: 18, boxShadow: '0 2px 8px rgba(0,0,0,0.08)', borderLeft: '4px solid #FFC107' },
  conductorHeader: { display: 'flex', alignItems: 'center', gap: 12, marginBottom: 12 },
  foto: { width: 48, height: 48, borderRadius: 24, objectFit: 'cover', border: '2px solid #FFC107' },
  fotoPlaceholder: { width: 48, height: 48, borderRadius: 24, background: '#FFC107', display: 'flex', alignItems: 'center', justifyContent: 'center', fontWeight: 'bold', fontSize: 20 },
  nombre: { margin: 0, fontWeight: 'bold', fontSize: 16 },
  placa: { margin: 0, color: '#FFC107', fontWeight: 'bold', letterSpacing: 2 },
  ubicacionInfo: {},
  coordenadas: { fontSize: 13, color: '#666', margin: '4px 0' },
  actualizado: { fontSize: 12, color: '#999', margin: '2px 0' },
  linkMapa: { fontSize: 13, color: '#1565C0', fontWeight: '600', textDecoration: 'none' },
};
